@@ -0,0 +1,28 @@
+import { describe, it, expect } from 'vitest';
+import { RateLimiter } from '../../src/utils/rate-limiter';
+
+describe('RateLimiter', () => {
+  it('allows requests under the limit', () => {
+    const limiter = new RateLimiter({ maxAttempts: 3, windowMs: 60000 });
+    limiter.record('key1');
+    limiter.record('key1');
+    expect(limiter.isAllowed('key1')).toBe(true);
+  });
+
+  it('blocks requests over the limit', () => {
+    const limiter = new RateLimiter({ maxAttempts: 2, windowMs: 60000 });
+    limiter.record('key1');
+    limiter.record('key1');
+    expect(limiter.isAllowed('key1')).toBe(false);
+  });
+
+  it('resets the counter for a key', () => {
+    const limiter = new RateLimiter({ maxAttempts: 1, windowMs: 60000 });
+    limiter.record('key1');
+    expect(limiter.isAllowed('key1')).toBe(false);
+    limiter.reset('key1');
+    expect(limiter.isAllowed('key1')).toBe(true);
+  });
+});
